 1	import type { V1beta1PlanStatusMigrationVmsPipeline } from '@kubev2v/types';
 2	import { Icon } from '@patternfly/react-core';
 3	import { CheckIcon, ResourcesEmptyIcon, TimesIcon } from '@patternfly/react-icons';
 4	import { taskStatuses } from '@utils/constants';
 5	
 6	export const getPipelineProgressIcon = (pipeline: V1beta1PlanStatusMigrationVmsPipeline) => {
 7	  if (pipeline?.error)
 8	    return (
 9	      <Icon status="danger">
10	        <TimesIcon />
11	      </Icon>
12	    );
13	  if (pipeline?.phase === taskStatuses.completed)
14	    return (
15	      <Icon status="success">
16	        <CheckIcon />
17	      </Icon>
18	    );
19	  return <ResourcesEmptyIcon />;
20	};

